        </p>

        <form action={handleSubmit}>
          <div className="form-group mb-6">
            <input 
              className="form-input text-center" 
              name="otp" 
              type="text" 
              placeholder="000000"
              maxLength={6}
              style={{ fontSize: '2rem', letterSpacing: '0.5rem', padding: '1rem' }}
              required 
