          </div>

          <button className="btn-primary" type="submit" disabled={loading}>
            {loading ? 'Verifying...' : 'Verify Code'}
          </button>

          {error && <div className="form-error">{error}</div>}
        </form>
      </div>
    </div>
  )
}"

