export async function verifySignupOtp(formData: FormData) {
  const supabase = await createClient()

  const email = formData.get('email') as string
  const token = formData.get('otp') as string

  if (!email || !token) {
    return { error: 'Email and OTP code are required' }
  }

  const { error, data } = await supabase.auth.verifyOtp({
    email,
    token,
    type: 'signup'
  })

  if (error) {
    return { error: 'Invalid or expired OTP code. Please try again.' }
  }

  // Verification successful! Supabase creates the session.
  revalidatePath('/', 'layout')
  redirect('/onboarding')
}

export async function logout() {
  const supabase = await createClient()
  await supabase.auth.signOut()
  redirect('/login')
}"

